commands.command:
kubectl apply -f - <<EOF
apiVersion: v1
kind: Pod
metadata:
  name: frontend
  namespace: case12-double
  labels:
    app: frontend
spec:
  containers:
  - name: frontend
    image: curlimages/curl:latest
    command: ["sh", "-c"]
    args:
    - echo "Frontend starting...";
      while true; do
        echo "Checking backend connectivity...";
        if curl -s --max-time 5 http://backend-svc:80 > /dev/null 2>&1; then
          echo "Backend is reachable!";
          sleep 10;
        else
          echo "Cannot connect to backend-svc:80";
          sleep 3;
        fi;
      done;
EOF
